+import { Inject, Injectable, Logger, OnModuleInit } from '@nestjs/common';
+import { ConfigType } from '@nestjs/config';
+import { ethers } from 'ethers';
+import { TronWeb } from 'tronweb';
+import { networksConfigs } from '@configs/networks.configs';
+import { SupportedNetworks } from '../types/network.type';
+
+export interface DerivedWallet {
+  address: string;
+  privateKey: string;
+}
+
+const BIP44_COIN_TYPES: Record<string, number> = {
+  [SupportedNetworks.ETHEREUM]: 60,
+  [SupportedNetworks.BNB]: 60,
+  [SupportedNetworks.TRON]: 195,
+};
+
+const HD_SUPPORTED_NETWORKS = [
+  SupportedNetworks.TRON,
+  SupportedNetworks.ETHEREUM,
+  SupportedNetworks.BNB,
+] as const;
+
+@Injectable()
+export class HdWalletService implements OnModuleInit {
+  private readonly logger = new Logger(HdWalletService.name);
+
+  /**
+   * Cached account-level HD nodes per network.
+   * Parsed once on init to avoid re-running PBKDF2 (2048 rounds) on every derivation.
+   * Each node sits at m/44'/coinType'/0'/0 — child derivation from here is a fast
+   * single HMAC-SHA512 operation.
+   */
+  private readonly accountNodes = new Map<
+    SupportedNetworks,
+    ethers.HDNodeWallet
+  >();
+
+  constructor(
+    @Inject(networksConfigs.KEY)
+    private readonly networksConfig: ConfigType<typeof networksConfigs>,
+  ) {}
+
+  onModuleInit(): void {
+    for (const network of HD_SUPPORTED_NETWORKS) {
+      const phrase = this.getMnemonicPhrase(network);
+
+      let mnemonic: ethers.Mnemonic;
+      try {
+        mnemonic = ethers.Mnemonic.fromPhrase(phrase);
+      } catch {
+        throw new Error(
+          `Invalid BIP-39 mnemonic for ${network}. Check the corresponding HD_MNEMONIC env var.`,
+        );
+      }
+
+      const coinType = BIP44_COIN_TYPES[network];
+      const accountPath = `m/44'/${coinType}'/0'/0`;
+      const accountNode = ethers.HDNodeWallet.fromMnemonic(
+        mnemonic,
+        accountPath,
+      );
+
+      this.accountNodes.set(network, accountNode);
+      this.logger.log({ message: `HD account node initialised`, network });
+    }
+  }
+
+  deriveWallet(network: SupportedNetworks, index: number): DerivedWallet {
+    const child = this.deriveChild(network, index);
+
+    if (network === SupportedNetworks.TRON) {
+      const rawKey = child.privateKey.slice(2);
+      const address = TronWeb.address.fromPrivateKey(rawKey) as string;
+      return { address, privateKey: rawKey };
+    }
+
+    return { address: child.address, privateKey: child.privateKey };
+  }
+
+  deriveAddress(network: SupportedNetworks, index: number): string {
+    return this.deriveWallet(network, index).address;
+  }
+
+  /**
+   * Derives the private key and verifies it matches the expected address.
+   * Throws if there is a mismatch (mnemonic changed, DB corruption, etc.).
+   */
+  deriveAndVerify(
+    network: SupportedNetworks,
+    index: number,
+    expectedAddress: string,
+  ): DerivedWallet {
+    const wallet = this.deriveWallet(network, index);
+    if (wallet.address !== expectedAddress) {
+      throw new Error(
+        `HD derivation mismatch for ${network} index ${index}: ` +
+          `expected ${expectedAddress}, got ${wallet.address}. ` +
+          `The mnemonic may have been changed or the DB record is corrupt.`,
+      );
+    }
+    return wallet;
+  }
+
+  private deriveChild(
+    network: SupportedNetworks,
+    index: number,
+  ): ethers.HDNodeWallet {
+    const accountNode = this.accountNodes.get(network);
+    if (!accountNode) {
+      throw new Error(`HD wallet not initialised for network: ${network}`);
+    }
+    return accountNode.deriveChild(index);
+  }
+
+  private getMnemonicPhrase(network: SupportedNetworks): string {
+    switch (network) {
+      case SupportedNetworks.TRON:
+        return this.networksConfig.tron.hdMnemonic;
+      case SupportedNetworks.ETHEREUM:
+        return this.networksConfig.ethereum.hdMnemonic;
+      case SupportedNetworks.BNB:
+        return this.networksConfig.bnb.hdMnemonic;
+      default:
+        throw new Error(`HD wallet not supported for network: ${network}`);
+    }
+  }
+}
