    31→   * Sweeps funds keeping min_deposit_pool_account_amount in the pool account
    32→   */
    33→  async monitorPoolAccounts(network: SupportedNetworks): Promise<void> {
    34→    const trx = await this.db.startTransaction().execute();
    35→    try {
    36→      // Get all pool accounts for
    37→      const poolAccounts = await trx
    38→        .selectFrom('depositPoolAccount')
    39→        // for update to prevent concurrent access
    40→        .forUpdate()
    41→        .selectAll()
    42→        .where('network', '=', network)
    43→        .where((eb) =>
    44→          eb.or([
    45→            eb('lastMonitorAt', 'is', null),
    46→            eb('lastMonitorAt', '<', new Date(Date.now() - 15 * 60 * 1000)), // Only check accounts that have not been monitored yet or lastMonitorAt was more then 15 minutes ago
    47→          ]),
    48→        )
    49→        .where((eb) =>
    50→          eb(
    51→            'id',
    52→            'not in',
    53→            eb
    54→              .selectFrom('depositPoolAccountLocks')
    55→              .select('depositPoolAccountId'),
