   213→
   214→      let sendAmountSun: Decimal;
   215→      if (params.amount) {
   216→        // params.amount is in TRX — convert to SUN before comparing with balanceSun
   217→        sendAmountSun = new Decimal(params.amount).mul(1_000_000);
   218→        const requiredSun = sendAmountSun.plus(feeSun);
   219→        if (requiredSun.gt(balanceSun)) {
